            if visited[r][c] or grid[r][c] != color:
                continue
            visited[r][c] = True
            cells.append((r, c))
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                stack.append((r+dr, c+dc))
        return cells

    for r in range(h):
        for c in range(w):
            if grid[r][c] != 0 and not visited[r][c]:
                color = grid[r][c]
